import React from "react";
import {
    View,
    TextInput,
    TouchableOpacity,
    StyleSheet,
    useWindowDimensions,
} from "react-native";
import type { IconName, IToolbarProps } from "@lmb/kitsconcerto-types";
import { IconMap } from "../../../../";

/* ------------------------------------------------------------------ */
/* Helpers                                                              */
/* ------------------------------------------------------------------ */

const Icon = ({ name, color = "#333", size = 16 }: { name: string; color?: string; size?: number }) => {
    const cleanName: IconName = name.replace("pi pi-", "") as IconName;
    const C = IconMap[cleanName];
    if (!C) return null;
    return <C size={size} color={color} />;
};

const ActionButton = ({
    icon,
    onPress,
    disabled,
    variant = "primary",
    hideDisabledButton,
}: {
    icon: string;
    onPress: () => void;
    disabled?: boolean;
    variant?: "primary" | "secondary" | "danger";
    hideDisabledButton?: boolean;
}) => {
    if (disabled && hideDisabledButton) return null;

    const bgColor =
        variant === "danger" ? "#ffebee"
            : variant === "secondary" ? "#f5f5f5"
                : "#e3f2fd";
    const iconColor =
        variant === "danger" ? "#d32f2f"
            : variant === "secondary" ? "#616161"
                : "#1976d2";

    return (
        <TouchableOpacity
            onPress={onPress}
            disabled={disabled}
            style={[
                styles.button,
                { backgroundColor: disabled ? "#f0f0f0" : bgColor, opacity: disabled ? 0.5 : 1 },
            ]}
        >
            <Icon name={icon} color={disabled ? "#aaa" : iconColor} />
        </TouchableOpacity>
    );
};

/* ------------------------------------------------------------------ */
/* TreeViewToolbar                                                      */
/* ------------------------------------------------------------------ */

const TreeViewToolbar = <T,>({
    props,
    filterValue,
    setFilterValue,
    treeRef,
    selectedNode,
    expandAll,
    collapseAll,
    onAddNode,
    onAddNodeItem,
    onDeleteNode,
    onEditNode,
    build,
}: IToolbarProps<T>) => {
    const { width } = useWindowDimensions();
    const isWide = width >= 768;

    const {
        expendableControls,
        serverSide,
        text,
        rules,
        hideDisabledButton,
    } = props;

    // --- Button visibility logic (same as web) ---
    const itemButton =
        (rules?.allowIndependentItem && rules?.addItem) ||
        (rules?.addItem && !!selectedNode && !selectedNode.data?.isItem);

    const categoryButton =
        (rules?.addCategory && !selectedNode) ||
        (rules?.addSubCategory && !!selectedNode && !selectedNode.data?.isItem);

    const deleteButton =
        !!selectedNode &&
        ((rules?.deleteCategory && !selectedNode.data?.isItem && !selectedNode.data?.parentId) ||
            (rules?.deleteSubCategory && !selectedNode.data?.isItem && !!selectedNode.data?.parentId) ||
            (rules?.deleteItem && !!selectedNode.data?.isItem));

    const editButton =
        !!selectedNode &&
        ((rules?.updateCategory && !selectedNode.data?.isItem && !selectedNode.data?.parentId) ||
            (rules?.updateSubCategory && !selectedNode.data?.isItem && !!selectedNode.data?.parentId) ||
            (rules?.updateItem && !!selectedNode.data?.isItem));

    /* ---- Search box ---- */
    const SearchBox = (
        <View style={styles.searchBox}>
            <Icon name="pi pi-search" color="#999" />
            <TextInput
                style={styles.searchInput}
                value={filterValue}
                placeholder="Search..."
                placeholderTextColor="#999"
                onChangeText={(val) => {
                    setFilterValue(val);
                    treeRef?.filter?.(val);
                }}
            />
        </View>
    );

    /* ---- Expand / Collapse / Refresh ---- */
    const ExpandButtons = (
        <View style={styles.btnGroup}>
            {!!expendableControls && (
                <>
                    <ActionButton icon="pi pi-angle-double-down" onPress={expandAll} variant="secondary" />
                    <ActionButton icon="pi pi-angle-double-up" onPress={collapseAll} variant="secondary" />
                </>
            )}
            {!!serverSide?.listFetcher && (
                <ActionButton icon="pi pi-refresh" onPress={build} variant="secondary" />
            )}
        </View>
    );

    /* ---- CRUD buttons ---- */
    const CrudButtons = (
        <View style={styles.btnGroup}>
            {((!hideDisabledButton && !categoryButton) || categoryButton) && (
                <ActionButton icon="pi pi-plus" onPress={() => onAddNode(selectedNode?.key)} disabled={!categoryButton} hideDisabledButton={hideDisabledButton} />
            )}
            {((!hideDisabledButton && !itemButton) || itemButton) && (
                <ActionButton icon="pi pi-plus" onPress={() => onAddNodeItem(selectedNode?.key)} disabled={!itemButton} variant="secondary" hideDisabledButton={hideDisabledButton} />
            )}
            {((!hideDisabledButton && !deleteButton) || deleteButton) && (
                <ActionButton icon="pi pi-trash" onPress={() => onDeleteNode(selectedNode?.key)} disabled={!deleteButton} variant="danger" hideDisabledButton={hideDisabledButton} />
            )}
            {((!hideDisabledButton && !editButton) || editButton) && (
                <ActionButton icon="pi pi-pencil" onPress={() => onEditNode(selectedNode?.key)} disabled={!editButton} variant="secondary" hideDisabledButton={hideDisabledButton} />
            )}
        </View>
    );

    /* ---- Layout ---- */

    if (isWide) {
        // iPad landscape: [Search ............] [Expand] [CRUD]
        return (
            <View style={styles.toolbarRow}>
                <View style={styles.searchSection}>{SearchBox}</View>
                {ExpandButtons}
                {CrudButtons}
            </View>
        );
    }

    // Phone: Search full width on top, buttons row below
    return (
        <View style={styles.toolbarColumn}>
            {SearchBox}
            <View style={styles.buttonsRow}>
                {ExpandButtons}
                {CrudButtons}
            </View>
        </View>
    );
};

/* ------------------------------------------------------------------ */
/* Styles                                                               */
/* ------------------------------------------------------------------ */

const styles = StyleSheet.create({
    // Wide layout (iPad landscape)
    toolbarRow: {
        flexDirection: "row",
        alignItems: "center",
        backgroundColor: "#f8f9fa",
        borderWidth: 1,
        borderColor: "#dee2e6",
        borderRadius: 6,
        paddingHorizontal: 12,
        paddingVertical: 8,
        gap: 12,
    },
    searchSection: {
        flex: 1,
        minWidth: 0,
    },

    // Narrow layout (phone)
    toolbarColumn: {
        backgroundColor: "#f8f9fa",
        borderWidth: 1,
        borderColor: "#dee2e6",
        borderRadius: 6,
        paddingHorizontal: 12,
        paddingVertical: 8,
        gap: 8,
    },
    buttonsRow: {
        flexDirection: "row",
        alignItems: "center",
        justifyContent: "space-between",
    },

    // Search input
    searchBox: {
        flexDirection: "row",
        alignItems: "center",
        backgroundColor: "#fff",
        borderRadius: 6,
        paddingHorizontal: 10,
        height: 40,
        borderWidth: 1,
        borderColor: "#ced4da",
    },
    searchInput: {
        flex: 1,
        marginLeft: 8,
        fontSize: 14,
        color: "#495057",
        paddingVertical: 0,
    },

    // Button groups
    btnGroup: {
        flexDirection: "row",
        alignItems: "center",
        gap: 4,
    },
    button: {
        width: 38,
        height: 38,
        borderRadius: 6,
        justifyContent: "center",
        alignItems: "center",
    },
});

export default TreeViewToolbar;
